mapper.select:
/* PromotionMapper.getChrgPrmtList */
SELECT A.PRMT_ID AS prmtId , A.PRMT_NM AS prmtNm , A.STRT_DT AS strtDt , A.END_DT AS endDt , A.NAC_YN AS nacYn , A.MNP_YN AS mnpYn , A.ORGN_TYPE AS orgnType , FN_GET_CODENM('CMN0055', A.ORGN_TYPE) AS orgnTypeNm , A.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9022', A.REQ_BUY_TYPE) AS reqBuyTypeNm , A.ENGG_CNT_0 AS enggCnt0 , A.ENGG_CNT_12 AS enggCnt12 , A.ENGG_CNT_18 AS enggCnt18 , A.ENGG_CNT_24 AS enggCnt24 , A.ENGG_CNT_30 AS enggCnt30 , A.ENGG_CNT_36 AS enggCnt36 , A.USG_YN AS usgYn , A.REGST_ID AS regstId , FN_GET_USRNM(A.REGST_ID) AS regstNm , A.REGST_DTTM AS regstDttm , A.RVISN_ID AS rvisnId , FN_GET_USRNM(A.RVISN_ID) AS rvisnNm , A.RVISN_DTTM AS rvisnDttm FROM MSP_CHRG_PRMT A WHERE #{searchBaseDate} BETWEEN A.STRT_DT AND A.END_DT
AND UPPER(A.PRMT_NM) LIKE '%' || UPPER( #{prmtNm} ) || '%'
AND A.ORGN_TYPE = #{orgnType}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND EXISTS (SELECT 1 FROM MSP_CHRG_PRMT_ONOFF WHERE PRMT_ID = A.PRMT_ID AND ON_OFF_TYPE = #{onOffType})
AND EXISTS (SELECT 1 FROM MSP_CHRG_PRMT_ORG B WHERE A.PRMT_ID = B.PRMT_ID
AND FN_GET_ORGNM(B.ORGN_ID) LIKE '%' || #{orgnVal} || '%'
AND B.ORGN_ID = #{orgnVal}
)
AND EXISTS (SELECT 1 FROM MSP_CHRG_PRMT_SOC C WHERE A.PRMT_ID = C.PRMT_ID
AND FN_GET_RATENM(C.RATE_CD) LIKE '%' || #{pRateVal} || '%'
AND C.RATE_CD = #{pRateVal}
)
AND EXISTS (SELECT 1 FROM MSP_CHRG_PRMT_ADD D WHERE A.PRMT_ID = D.PRMT_ID
AND FN_GET_RATENM(D.SOC) LIKE '%' || #{rRateVal} || '%'
AND D.SOC = #{rRateVal}
)
AND A.USG_YN = 'Y' ORDER BY A.REGST_DTTM DESC

/* PromotionMapper.getChrgPrmtOrgnList */ SELECT DECODE(C.ORGN_ID, NULL, '0', '1') AS rowCheck , A.ORGN_ID AS orgnId , A.ORGN_NM AS orgnNm , B.CD_DSC AS typeNm , FN_GET_CODENM('CMN0005', A.ORGN_STAT_CD) AS statNm FROM ORG_ORGN_INFO_MST A , CMN_GRP_CD_MST B , MSP_CHRG_PRMT_ORG C WHERE A.TYPE_DTL_CD3 = B.CD_VAL AND A.ORGN_ID = C.ORGN_ID(+) AND A.TYPE_CD = '20' -- 대리점 AND A.ORGN_STAT_CD = '4' -- 가동 AND B.GRP_ID = 'ORG0043' AND B.USG_YN = 'Y' AND C.PRMT_ID(+) = #{prmtId}
AND A.TYPE_DTL_CD2 = #{orgnType}
AND A.ORGN_NM LIKE '%'||#{orgnNm}||'%'
ORDER BY rowCheck DESC, orgnNm

/* PromotionMapper.getChrgPrmtSocList */ SELECT DECODE(B.RATE_CD, NULL, '0', '1') AS rowCheck ,A.RATE_CD AS rateCd ,A.RATE_NM AS rateNm ,A.DATA_TYPE AS dataType ,A.BASE_AMT AS baseAmt FROM MSP_RATE_MST A ,MSP_CHRG_PRMT_SOC B WHERE A.RATE_CD = B.RATE_CD(+) AND A.APPL_END_DT = '99991231' AND A.SERVICE_TYPE = 'P' AND A.PAY_CL_CD = 'PO'
AND A.DATA_TYPE = #{dataType}
AND B.PRMT_ID(+) = #{prmtId} ORDER BY rowCheck DESC, dataType DESC, rateNm

