/* PromotionMapper.updChrgPrmtByInfo */
UPDATE  MSP_CHRG_PRMT
SET     RVISN_ID = #{sessionUserId}
		,RVISN_DTTM = SYSDATE



					,USG_YN = NVL(#{usgYn}, 'N')


