mapper.sql:
SELECT A.COMMEND_ID AS commendId /* 추천인ID */ , A.CONTRACT_NUM AS contractNum /* 추천인 계약번호 */ , B.SUB_LINK_NAME AS subLinkName /* 추천인 고객명 */ , B.SUBSCRIBER_NO AS subscriberNo /* 추천인 휴대폰번호 */ , TO_CHAR(A.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS') AS sysRdate /* 발급일자 */ , FN_GET_CODENM('CMN0287', A.LINK_TYPE_CD) AS linkTypeNm /* 링크유형 */ , PI.BF_COMM_CMPN_NM AS bfCommCmpnNm /* 이동전 통신사 */ FROM MCP_COMMEND_ID_MNG@dl_mcp A, MSP_JUO_SUB_INFO B, MDS_PORTIN_MST PI WHERE A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.CONTRACT_NUM = PI.CONTRACT_NUM(+)
AND TO_CHAR(A.SYS_RDATE, 'YYYYMMDD') BETWEEN #{searchFromDt} AND #{searchToDt}
AND A.COMMEND_ID = #{searchVal}
AND A.CONTRACT_NUM = #{searchVal}
AND B.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND B.SUBSCRIBER_NO = #{searchVal}
AND A.LINK_TYPE_CD = #{linkTypeCd}
ORDER BY sysRdate DESC

SELECT C.COMMEND_ID AS commendId /* 추천인ID */ , B.LINK_TYPE_CD AS linkTypeCd /* 링크유형코드 */ , FN_GET_CODENM('CMN0287', B.LINK_TYPE_CD) AS linkTypeNm /* 링크유형 */ , TO_CHAR(B.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS') AS sysRdate /* 발급일자 */ , C.CONTRACT_NUM AS contractNum /* 추천인 계약번호 */ , A1.SUB_LINK_NAME AS subLinkName /* 추천인 고객명 */ , A1.SUBSCRIBER_NO AS subscriberNo /* 추천인 휴대폰번호 */ , SUBSTR(CRYPTO_AES256.DEC_AES(A1.USER_SSN),0,6) AS birthDt /* 추천인 생년월일 */ , D.LST_RATE_CD AS rateCd /* 추천인 현재 요금제코드 */ , D.LST_RATE_NM AS rateNm /* 추천인 현재 요금제명 */ , F.BF_COMM_CMPN_NM AS bfCommCmpnNm /* 추천인 이동전 통신사 */ , NVL((SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE A1.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS orgnNm /* 추천인 유심접점*/ , D.EVNT_CD_PRMT AS evntCdPrmt /* 추천인 이벤트코드*/ , FN_GET_CODENM('MSP0003', A1.SUB_STATUS) AS subStatus /* 추천인 계약상태 */
, B.CONTRACT_NUM AS dContractNum /* 피추천인 계약번호 */ , A2.SVC_CNTR_NO AS dSvcCntrNo /* 피추천인 서비스 계약번호 */ , A2.SUB_LINK_NAME AS deSubLinkName /* 피추천인 이름 */ , E.OPER_TYPE_NM AS dOperTypeNm /* 피추천인 업무구분 */ , F.BF_COMM_CMPN_NM AS dBfCommCmpnNm /* 피추천인 이동전 통신사 */ , A2.SUBSCRIBER_NO AS deSubscriberNo /* 피추천인 휴대폰번호 */ , E.FST_RATE_CD AS dFstRateCd /* 피추천인 최초요금제코드 */ , E.FST_RATE_NM AS dFstRateNm /* 피추천인 최초요금제 */ , E.LST_RATE_CD AS dLstRateCd /* 피추천인 현재요금제코드 */ , E.LST_RATE_NM AS dLstRateNm /* 피추천인 현재요금제 */ , FN_GET_ORGNM(A2.OPEN_AGNT_CD) AS dOpenAgntNm /* 대리점*/ , E.REQ_BUY_TYPE_NM AS dReqBuyTypeNm /* 구매유형*/ , TO_CHAR(TO_DATE(E.REQ_IN_DAY, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD') AS dReqInDay /* 피추천인 신청일자*/ , TO_CHAR(TO_DATE(A2.LST_COM_ACTV_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD') AS dLstComActvDate /* 피추천인 개통일자 */ , TO_CHAR(TO_DATE(DECODE(A2.SUB_STATUS,'C',SUBSTR(A2.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS dSubStatusDate /* 해지일자 */ , NVL((SELECT (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = PUM.ORGN_ID AND ROWNUM = 1) FROM MSP_PARTNER_USIM_MST PUM WHERE A2.ICC_ID = PUM.USIM_NO), 'M모바일(직영온라인)') AS dOrngNm /* 피추천인 유심접점 */ , DECODE(A2.GENDER,'1','남자','2','여자','기타') AS dGender /* 피추천인 성별 */ , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(A2.USER_SSN), '-', ''), 0, 6) AS dBirthDt /* 피추천인 생년월일 */ , FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(A2.USER_SSN)) AS dAge /* 피추천인 나이 */ , E.EVNT_CD_PRMT AS dEvntCdPrmt /* 피추천인 이벤트코드*/ , FN_GET_CODENM('MSP0003', A2.SUB_STATUS) AS dSubStatus /* 피추천인 계약상태 */ , DECODE(H.STATUS, '사용중', 'Y', 'N') AS dInetStatus /* 피추천인 인터넷 가입여부 */ , DECODE(B.LINK_TYPE_CD,'99', FN_GET_RATENM(B.COMMEND_SOC_CODE_01), '') AS commendSocCode01 /* 추천요금제1 */ , DECODE(B.LINK_TYPE_CD,'99', FN_GET_RATENM(B.COMMEND_SOC_CODE_02), '') AS commendSocCode02 /* 추천요금제2 */ , DECODE(B.LINK_TYPE_CD,'99', FN_GET_RATENM(B.COMMEND_SOC_CODE_03), '') AS commendSocCode03 /* 추천요금제3 */ FROM MSP_JUO_SUB_INFO A1 /*추천인*/ , MSP_JUO_SUB_INFO A2 /*피추천인*/ , ( SELECT A.COMMEND_ID , A.APPLY_YN , A.APPLY_DATE , A.REQUEST_KEY , A.RES_NO , A.SYS_RDATE , A.RVISN_DTTM , B.CONTRACT_NUM , A.LINK_TYPE_CD , A.COMMEND_SOC_CODE_01 , A.COMMEND_SOC_CODE_02 , A.COMMEND_SOC_CODE_03 FROM MCP_REQUEST_COMMEND@DL_MCP A , MCP_REQUEST@DL_MCP B WHERE A.REQUEST_KEY = B.REQUEST_KEY AND B.PSTATE = '00' AND B.REQUEST_STATE_CODE = '21' ) B , MCP_COMMEND_ID_MNG@DL_MCP C , MSP_REQUEST_DTL D /*추천인*/ , MSP_REQUEST_DTL E /*피추천인*/ , MDS_PORTIN_MST F /*추천인*/ , MDS_PORTIN_MST G /*피추천인*/ , MSP_INET_INFO_MST H /*피추천인*/ WHERE A1.CONTRACT_NUM = C.CONTRACT_NUM AND A2.CONTRACT_NUM = B.CONTRACT_NUM AND B.COMMEND_ID = C.COMMEND_ID AND D.CONTRACT_NUM = C.CONTRACT_NUM AND E.CONTRACT_NUM = B.CONTRACT_NUM AND A1.CONTRACT_NUM = F.CONTRACT_NUM(+) AND A2.CONTRACT_NUM = G.CONTRACT_NUM(+) AND A2.CUSTOMER_ID = H.CUST_ID(+)
AND A2.LST_COM_ACTV_DATE BETWEEN #{searchFromDt} AND #{searchToDt}
AND B.APPLY_YN = #{appType}
AND B.LINK_TYPE_CD = #{linkTypeCd}
AND C.COMMEND_ID = #{searchVal}
AND C.CONTRACT_NUM = #{searchVal}
AND A1.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND A1.SUBSCRIBER_NO = #{searchVal}
AND B.CONTRACT_NUM = #{deSearchVal}
AND A2.SUB_LINK_NAME LIKE #{deSearchVal} || '%'
AND A2.SUBSCRIBER_NO = #{deSearchVal}
ORDER BY B.SYS_RDATE DESC

mapper.select:
/*PromotionMapper.getChrgPrmtDupByInfoExl*/
SELECT  DISTINCT
		A.PRMT_ID				AS prmtId
		,B.ORGN_ID				AS orgnId
		,C.RATE_CD				AS rateCd
		,D.ON_OFF_TYPE			AS onOffType
		,'1'                    AS chrgTypeCd
FROM    MSP_CHRG_PRMT A
		,MSP_CHRG_PRMT_ORG B
		,MSP_CHRG_PRMT_SOC C
		,MSP_CHRG_PRMT_ONOFF D
WHERE   A.USG_YN = 'Y'
	AND A.PRMT_ID = B.PRMT_ID
	AND A.PRMT_ID = C.PRMT_ID
	AND A.PRMT_ID = D.PRMT_ID
	AND #{strtDt} <= A.END_DT
	AND #{endDt} >= A.STRT_DT
	AND A.REQ_BUY_TYPE = #{reqBuyType}
	AND ((A.NAC_YN = 'Y' AND A.MNP_YN = 'Y')

	OR A.NAC_YN = #{nacYn}


	OR A.MNP_YN = #{mnpYn}

		)
	AND ((A.ENGG_CNT_0 = 'Y' AND A.ENGG_CNT_12 = 'Y' AND A.ENGG_CNT_18 = 'Y' AND A.ENGG_CNT_24 = 'Y' AND A.ENGG_CNT_30 = 'Y' AND A.ENGG_CNT_36 = 'Y')

	OR A.ENGG_CNT_0 = #{enggCnt0}


	OR A.ENGG_CNT_12 = #{enggCnt12}


	OR A.ENGG_CNT_18 = #{enggCnt18}


	OR A.ENGG_CNT_24 = #{enggCnt24}


	OR A.ENGG_CNT_30 = #{enggCnt30}


	OR A.ENGG_CNT_36 = #{enggCnt36}

		)
UNION
SELECT DISTINCT
		A.PRMT_ID				AS prmtId
		,B.ORGN_ID				AS orgnId
		,C.RATE_CD				AS rateCd
		,D.ON_OFF_TYPE 			AS onOffType
		,'2'                    AS chrgTypeCd
FROM    MSP_DIS_MST_CHK A
		,MSP_DIS_ORG_CHK B
		,MSP_DIS_SOC_CHK C
		,MSP_CHRG_PRMT_ONOFF_CHK D
WHERE   A.USG_YN = 'Y'
	AND A.PRMT_ID = B.PRMT_ID
	AND A.PRMT_ID = C.PRMT_ID
	AND A.PRMT_ID = D.PRMT_ID
	AND #{strtDt} <= A.END_DTTM
	AND #{endDt} >= A.STRT_DTTM
	AND A.REQ_BUY_TYPE = #{reqBuyType}
	AND ((A.NAC_YN = 'Y' AND A.MNP_YN = 'Y')

	OR A.NAC_YN = #{nacYn}


	OR A.MNP_YN = #{mnpYn}

		)
	AND ((A.ENGG_CNT_0 = 'Y' AND A.ENGG_CNT_12 = 'Y' AND A.ENGG_CNT_18 = 'Y' AND A.ENGG_CNT_24 = 'Y' AND A.ENGG_CNT_30 = 'Y' AND A.ENGG_CNT_36 = 'Y')

	OR A.ENGG_CNT_0 = #{enggCnt0}


	OR A.ENGG_CNT_12 = #{enggCnt12}


	OR A.ENGG_CNT_18 = #{enggCnt18}


	OR A.ENGG_CNT_24 = #{enggCnt24}


	OR A.ENGG_CNT_30 = #{enggCnt30}


	OR A.ENGG_CNT_36 = #{enggCnt36}

		)

