mapper.select:
/*PromotionMapper.getChoChrgPrmtListExcelDown*/ SELECT DENSE_RANK() OVER (ORDER BY A.PRMT_ID) AS rnum , A.PRMT_NM AS prmtNm , TO_CHAR(SYSDATE+1, 'YYYYMMDD') AS strtDt , '20991231' AS endDt , A.ORGN_TYPE AS orgnType , A.REQ_BUY_TYPE AS reqBuyType , A.NAC_YN AS nacYn , A.MNP_YN AS mnpYn , A.ENGG_CNT_0 AS enggCnt0 , A.ENGG_CNT_12 AS enggCnt12 , A.ENGG_CNT_18 AS enggCnt18 , A.ENGG_CNT_24 AS enggCnt24 , A.ENGG_CNT_30 AS enggCnt30 , A.ENGG_CNT_36 AS enggCnt36 , '조직코드' AS orgnId , C.RATE_CD AS rateCd , D.ON_OFF_TYPE AS onOffType , E.SOC AS soc FROM MSP_CHRG_PRMT A , MSP_CHRG_PRMT_SOC C , MSP_CHRG_PRMT_ONOFF D , MSP_CHRG_PRMT_ADD E WHERE 1=1 AND A.PRMT_ID IN
#{item}
AND A.PRMT_ID = C.PRMT_ID AND A.PRMT_ID = D.PRMT_ID AND A.PRMT_ID = E.PRMT_ID

/*PromotionMapper.getChrgPrmtDtlAllChk*/
SELECT  DISTINCT
        A.PRMT_ID		AS prmtId
        , B.ORGN_ID		AS orgnId
        , C.RATE_CD		AS rateCd
        , D.ON_OFF_TYPE AS onOffType
FROM    MSP_CHRG_PRMT A
        , MSP_CHRG_PRMT_ORG B
        , MSP_CHRG_PRMT_SOC C
        , MSP_CHRG_PRMT_ONOFF D
WHERE   A.USG_YN = 'Y'
AND     A.PRMT_ID = B.PRMT_ID
AND     A.PRMT_ID = C.PRMT_ID
AND     A.PRMT_ID = D.PRMT_ID
AND     #{strtDt} <= A.END_DT
AND     #{endDt} >= A.STRT_DT
AND     A.REQ_BUY_TYPE = #{reqBuyType}
AND     ((A.NAC_YN = 'Y' AND A.MNP_YN = 'Y')

            OR A.NAC_YN = #{nacYn}


            OR A.MNP_YN = #{mnpYn}

        )
AND     ((A.ENGG_CNT_0 = 'Y' AND A.ENGG_CNT_12 = 'Y' AND A.ENGG_CNT_18 = 'Y' AND A.ENGG_CNT_24 = 'Y' AND A.ENGG_CNT_30 = 'Y' AND A.ENGG_CNT_36 = 'Y') 

            OR A.ENGG_CNT_0 = #{enggCnt0}


            OR A.ENGG_CNT_12 = #{enggCnt12}


            OR A.ENGG_CNT_18 = #{enggCnt18}


            OR A.ENGG_CNT_24 = #{enggCnt24}


            OR A.ENGG_CNT_30 = #{enggCnt30}


            OR A.ENGG_CNT_36 = #{enggCnt36}

        )

AND     B.ORGN_ID IN (SELECT ORG.ORGN_ID FROM MSP_CHRG_PRMT_ORG ORG WHERE ORG.PRMT_ID = #{prmtId})
AND     C.RATE_CD IN (SELECT SOC.RATE_CD FROM MSP_CHRG_PRMT_SOC SOC WHERE SOC.PRMT_ID = #{prmtId})
AND     D.ON_OFF_TYPE IN (SELECT MCPO.ON_OFF_TYPE FROM MSP_CHRG_PRMT_ONOFF MCPO WHERE MCPO.PRMT_ID = #{prmtId})
AND     A.PRMT_ID NOT IN (#{prmtId})

ORDER BY B.ORGN_ID, C.RATE_CD, D.ON_OFF_TYPE
